package com.chaobo.scm.supplier.domain.contract;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import org.junit.jupiter.api.Test;import java.time.*;import java.util.concurrent.atomic.*;import static org.assertj.core.api.Assertions.*;
class SupplierContractAggregateTest{private final I i=new I();@Test void shouldApproveRenewAndTerminate(){var c=SupplierContractAggregate.create(1,2L,"PA-1","FRAMEWORK",LocalDate.now(),LocalDate.now().plusDays(30),"付款及质量条款","https://a",1,i);c.submit(1,i);c.approve(2,i);c.renew(LocalDate.now().plusDays(60),2,i);c.terminate("合作结束",2,i);assertThat(c.status()).isEqualTo(ContractStatus.TERMINATED);assertThat(c.pullEvents()).hasSize(5);}@Test void shouldModifyDraftAndRejectModificationAfterSubmit(){var c=SupplierContractAggregate.create(1,null,null,"FRAMEWORK",LocalDate.now(),LocalDate.now().plusDays(30),"原条款","https://old",1,i);c.pullEvents();c.modifyDraft(LocalDate.now().plusDays(45),"新条款","https://new",2,i);assertThat(c.to()).isEqualTo(LocalDate.now().plusDays(45));assertThat(c.terms()).isEqualTo("新条款");assertThat(c.attachment()).isEqualTo("https://new");assertThat(c.pullEvents()).extracting(e->e.eventType()).containsExactly("SupplierContractDraftModified");c.submit(2,i);assertThatThrownBy(()->c.modifyDraft(LocalDate.now().plusDays(50),"再次修改","https://new",2,i)).isInstanceOf(com.chaobo.scm.common.error.BusinessException.class);}@Test void shouldExpireActivePastContract(){var c=SupplierContractAggregate.create(1,null,null,"FRAMEWORK",LocalDate.now().minusDays(10),LocalDate.now().minusDays(1),"付款条款","https://a",1,i);c.submit(1,i);c.approve(1,i);c.expire(0,i);assertThat(c.status()).isEqualTo(ContractStatus.EXPIRED);assertThat(c.pullEvents()).extracting(e->e.eventType()).contains("SupplierContractExpired");}@Test void shouldReturnToDraftOnApprovalRejection(){var c=SupplierContractAggregate.create(1,null,null,"FRAMEWORK",LocalDate.now(),LocalDate.now().plusDays(30),"付款条款","https://a",1,i);c.submit(1,i);c.rejectApproval("附件签章不完整",2,i);assertThat(c.status()).isEqualTo(ContractStatus.DRAFT);}static class I implements IdentifierGenerator{AtomicLong n=new AtomicLong();public long nextId(){return n.incrementAndGet();}public String nextBusinessNo(String p){return p+nextId();}}}
